// Parsers for JUnit XML and JSON test result formats

import { DOMParser } from "@xmldom/xmldom";
import type { ParsedRun, TestCase, TestSuite, TestStatus } from "./types";

// --- JUnit XML Parser ---

export function parseJUnitXml(xmlContent: string, runId: string): ParsedRun {
  let doc: Document;
  let parseError = false;

  // @xmldom/xmldom writes parse errors to a custom error handler
  const parser = new DOMParser({
    errorHandler: {
      error: () => { parseError = true; },
      fatalError: () => { parseError = true; },
      warning: () => {},
    },
  });

  doc = parser.parseFromString(xmlContent, "text/xml") as unknown as Document;

  if (parseError) {
    throw new Error(`Failed to parse JUnit XML for run "${runId}": invalid XML`);
  }

  const root = doc.documentElement;
  if (!root) {
    throw new Error(`Failed to parse JUnit XML for run "${runId}": empty document`);
  }

  // Support both <testsuites> root and <testsuite> as root
  const suiteElements =
    root.tagName === "testsuites"
      ? Array.from(root.getElementsByTagName("testsuite"))
      : [root];

  const suites: TestSuite[] = suiteElements.map((suiteEl) => {
    const suiteName = suiteEl.getAttribute("name") ?? "unknown";
    const testCaseElements = Array.from(suiteEl.getElementsByTagName("testcase")).filter(
      (el) => el.parentNode === suiteEl
    );

    const tests: TestCase[] = testCaseElements.map((tcEl) => {
      const name = tcEl.getAttribute("name") ?? "unknown";
      const classname = tcEl.getAttribute("classname") ?? undefined;
      const duration = parseFloat(tcEl.getAttribute("time") ?? "0") || 0;

      let status: TestStatus = "passed";
      let failureMessage: string | undefined;

      const failureEl = tcEl.getElementsByTagName("failure")[0];
      const errorEl = tcEl.getElementsByTagName("error")[0];
      const skippedEl = tcEl.getElementsByTagName("skipped")[0];

      if (failureEl) {
        status = "failed";
        failureMessage = failureEl.getAttribute("message") ?? undefined;
      } else if (errorEl) {
        status = "error";
        failureMessage = errorEl.getAttribute("message") ?? undefined;
      } else if (skippedEl) {
        status = "skipped";
      }

      return { name, classname, duration, status, failureMessage };
    });

    return { name: suiteName, runId, tests };
  });

  return { runId, suites };
}

// --- JSON Parser ---

interface JsonTestCase {
  name: string;
  status: string;
  duration: number;
  classname?: string;
  failureMessage?: string;
}

interface JsonTestSuite {
  name: string;
  tests: JsonTestCase[];
}

interface JsonResultFile {
  runId?: string;
  testSuites?: JsonTestSuite[];
}

export function parseJsonResults(jsonContent: string, runId: string): ParsedRun {
  let data: JsonResultFile;

  try {
    data = JSON.parse(jsonContent) as JsonResultFile;
  } catch (err) {
    throw new Error(`Failed to parse JSON results for run "${runId}": ${String(err)}`);
  }

  if (!data.testSuites) {
    throw new Error(
      `Invalid JSON result file for run "${runId}": missing "testSuites" array`
    );
  }

  const effectiveRunId = data.runId ?? runId;

  const suites: TestSuite[] = data.testSuites.map((suiteData) => {
    const tests: TestCase[] = suiteData.tests.map((tc) => {
      const status = normalizeStatus(tc.status);
      return {
        name: tc.name,
        classname: tc.classname,
        duration: tc.duration ?? 0,
        status,
        failureMessage: tc.failureMessage,
      };
    });
    return { name: suiteData.name, runId: effectiveRunId, tests };
  });

  return { runId: effectiveRunId, suites };
}

function normalizeStatus(s: string): TestStatus {
  switch (s.toLowerCase()) {
    case "passed":
    case "pass":
      return "passed";
    case "failed":
    case "fail":
      return "failed";
    case "skipped":
    case "skip":
      return "skipped";
    case "error":
      return "error";
    default:
      return "passed";
  }
}

