  const suites: TestSuite[] = suiteElements.map((suiteEl) => {
    const suiteName = suiteEl.attrs.name ?? "unknown";
    const testCaseEls = suiteEl.children.filter((c) => c.tag === "testcase");

    const tests: TestCase[] = testCaseEls.map((tcEl) => {
